def unique_paths(R, C, obstacles=None):
    dp = [[0]*C for _ in range(R)]
    dp[0][0] = 1 if (not obstacles or obstacles[0][0] == 0) else 0
    for r in range(R):
        for c in range(C):
            if obstacles and obstacles[r][c] == 1:
                dp[r][c] = 0
                continue
            if r > 0: dp[r][c] += dp[r-1][c]
            if c > 0: dp[r][c] += dp[r][c-1]
    return dp[R-1][C-1]

