vector<vector<int>> floodFill(vector<vector<int>>& image, int sr, int sc, int newColor) {
    int R = image.size(), C = image[0].size();
    int startColor = image[sr][sc];
    if (startColor == newColor) return image;
    function<void(int,int)> dfs = [&](int r, int c) {
        if (r < 0 || r >= R || c < 0 || c >= C) return;
        if (image[r][c] != startColor) return;
        image[r][c] = newColor;
        dfs(r+1, c); dfs(r-1, c);
        dfs(r, c+1); dfs(r, c-1);
    };
    dfs(sr, sc);
    return image;
}

public int[][] floodFill(int[][] image, int sr, int sc, int newColor) {
    int R = image.length, C = image[0].length;
    int startColor = image[sr][sc];
    if (startColor == newColor) return image;
    dfs(image, sr, sc, startColor, newColor, R, C);
    return image;
}
void dfs(int[][] image, int r, int c, int startColor, int newColor, int R, int C) {
    if (r < 0 || r >= R || c < 0 || c >= C) return;
    if (image[r][c] != startColor) return;
    image[r][c] = newColor;
    dfs(image, r+1, c, startColor, newColor, R, C);
    dfs(image, r-1, c, startColor, newColor, R, C);
    dfs(image, r, c+1, startColor, newColor, R, C);
    dfs(image, r, c-1, startColor, newColor, R, C);
}

