from collections import deque

def shortest_path_with_elimination(grid, k):
    R, C = len(grid), len(grid[0])
    if R == 1 and C == 1:
        return 0

    INF = 10**9
    dist = [[[INF]*(k+1) for _ in range(C)] for _ in range(R)]
    q = deque()

    for kk in range(k+1):
        dist[0][0][kk] = 0
    q.append((0, 0, k))

    while q:
        r, c, kk = q.popleft()
        d = dist[r][c][kk]

        for dr, dc in [(1,0),(-1,0),(0,1),(0,-1)]:
            nr, nc = r+dr, c+dc
            if 0 <= nr < R and 0 <= nc < C:
                nk = kk - (grid[nr][nc] == 1)
                if nk >= 0 and dist[nr][nc][nk] > d + 1:
                    dist[nr][nc][nk] = d + 1
                    q.append((nr, nc, nk))

    ans = min(dist[R-1][C-1])
    return ans if ans != INF else -1

int shortestPathWithElimination(vector<vector<int>>& grid, int k) {
    int R = grid.size(), C = grid[0].size();
    if (R == 1 && C == 1) return 0;
    const int INF = 1e9;
    vector<vector<vector<int>>> dist(R, vector<vector<int>>(C, vector<int>(k+1, INF)));
    queue<tuple<int,int,int>> q;
    for (int kk = 0; kk <= k; kk++) dist[0][0][kk] = 0;
    q.push({0, 0, k});
    int dr[] = {1, -1, 0, 0};
    int dc[] = {0, 0, 1, -1};
    while (!q.empty()) {
        auto [r, c, kk] = q.front(); q.pop();
        int d = dist[r][c][kk];
        for (int i = 0; i < 4; i++) {
            int nr = r + dr[i], nc = c + dc[i];
            if (nr >= 0 && nr < R && nc >= 0 && nc < C) {
                int nk = kk - (grid[nr][nc] == 1);
                if (nk >= 0 && dist[nr][nc][nk] > d + 1) {
                    dist[nr][nc][nk] = d + 1;
                    q.push({nr, nc, nk});
                }
            }
        }
    }
    int ans = *min_element(dist[R-1][C-1].begin(), dist[R-1][C-1].end());
    return ans >= INF ? -1 : ans;
}

public int shortestPathWithElimination(int[][] grid, int k) {
    int R = grid.length, C = grid[0].length;
    if (R == 1 && C == 1) return 0;
    int INF = (int)1e9;
    int[][][] dist = new int[R][C][k+1];
    for (int[][] mat : dist) for (int[] row : mat) Arrays.fill(row, INF);
    Queue<int[]> q = new LinkedList<>();
    for (int kk = 0; kk <= k; kk++) dist[0][0][kk] = 0;
    q.offer(new int[]{0, 0, k});
    int[] dr = {1, -1, 0, 0};
    int[] dc = {0, 0, 1, -1};
    while (!q.isEmpty()) {
        int[] cur = q.poll();
        int r = cur[0], c = cur[1], kk = cur[2];
        int d = dist[r][c][kk];
        for (int i = 0; i < 4; i++) {
            int nr = r + dr[i], nc = c + dc[i];
            if (nr >= 0 && nr < R && nc >= 0 && nc < C) {
                int nk = kk - (grid[nr][nc] == 1 ? 1 : 0);
                if (nk >= 0 && dist[nr][nc][nk] > d + 1) {
                    dist[nr][nc][nk] = d + 1;
                    q.offer(new int[]{nr, nc, nk});
                }
            }
        }
